-- Create "payload_rules" table
CREATE TABLE "payload_rules" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "enabled" boolean NOT NULL DEFAULT true,
  "priority" bigint NOT NULL DEFAULT 0,
  "action" character varying NOT NULL,
  "match_model" character varying NOT NULL DEFAULT '*',
  "match_protocol" character varying NOT NULL DEFAULT '',
  "params_json" jsonb NULL,
  PRIMARY KEY ("id")
);
-- Create index "payloadrule_enabled" to table: "payload_rules"
CREATE INDEX "payloadrule_enabled" ON "payload_rules" ("enabled");
-- Create index "payloadrule_priority" to table: "payload_rules"
CREATE INDEX "payloadrule_priority" ON "payload_rules" ("priority");
